class AllOne {
    private class Node {
        int val;
        Set<String> keys = new HashSet<>();
        Node prev, next;
    }
    private final Map<String, Node> map = new HashMap<>();
    private final Node head, tail;

    public AllOne() {
        head = new Node();
        tail = new Node();
        head.next = tail;
        tail.prev = head;
    }

    public void inc(String key) {
        if (map.containsKey(key)) {
            Node node = map.get(key);
            node.keys.remove(key);
            Node next = node.next;
            if (next == tail || next.val != node.val + 1) {
                next = insertAfter(node, node.val + 1);
            }
            next.keys.add(key);
            map.put(key, next);
            if (node.keys.isEmpty()) remove(node);
        } else {
            Node first = head.next;
            if (first == tail || first.val != 1) {
                first = insertAfter(head, 1);
            }
            first.keys.add(key);
            map.put(key, first);
        }
    }

    public void dec(String key) {
        Node node = map.get(key);
        node.keys.remove(key);
        if (node.val == 1) {
            map.remove(key);
        } else {
            Node prev = node.prev;
            if (prev == head || prev.val != node.val - 1) {
                prev = insertAfter(node.prev, node.val - 1);
            }
            prev.keys.add(key);
            map.put(key, prev);
        }
        if (node.keys.isEmpty()) remove(node);
    }

    public String getMaxKey() {
        return tail.prev == head ? "" : tail.prev.keys.iterator().next();
    }

    public String getMinKey() {
        return head.next == tail ? "" : head.next.keys.iterator().next();
    }

    private Node insertAfter(Node node, int val) {
        Node newNode = new Node();
        newNode.val = val;
        newNode.prev = node;
        newNode.next = node.next;
        node.next.prev = newNode;
        node.next = newNode;
        return newNode;
    }

    private void remove(Node node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }
}
